import { z } from "zod";

// Registration schema with all fields and conditional validation
export const registrationSchema = z
  .object({
    username: z.string().min(3, "Username deve contenere almeno 3 caratteri"),
    email: z.string().email("Email non valida"),
    role: z.enum(["user", "admin", "contributor"]),
    otherInfo: z.string().optional(),
    newsletter: z.boolean(),
    frequency: z.enum(["daily", "weekly", "monthly"]).optional(),
    bio: z.string().optional(),
  })
  .superRefine((data, ctx) => {
    // otherInfo is required when role is "contributor"
    if (data.role === "contributor" && !data.otherInfo?.trim()) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Info sul contributo sono richieste",
        path: ["otherInfo"],
      });
    }

    // frequency is required when newsletter is true
    if (data.newsletter && !data.frequency) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Seleziona una frequenza",
        path: ["frequency"],
      });
    }
  });

// TypeScript type inferred from schema
export type RegistrationFormValues = z.infer<typeof registrationSchema>;

// Initial values: all optional fields get a safe default
export const registrationInitialValues: RegistrationFormValues = {
  username: "",
  email: "",
  role: "user",
  otherInfo: "",
  newsletter: false,
  frequency: undefined,
  bio: "",
};

// Role options for ControlledRadioGroup
export const roleOptions = [
  { value: "user", label: "User" },
  { value: "admin", label: "Admin" },
  { value: "contributor", label: "Contributor" },
] as const;

// Frequency options for frequency radio group
export const frequencyOptions = [
  { value: "daily", label: "Daily" },
  { value: "weekly", label: "Weekly" },
  { value: "monthly", label: "Monthly" },
] as const;

