import { z } from "zod";

const baseSchema = z.object({
  username: z.string().min(3, "Username must be at least 3 characters long"),
  email: z.string().email("Please enter a valid email address"),
  role: z.enum(["user", "admin", "contributor"], "Please select a role"),
  otherInfo: z.string().optional(),
  newsletter: z.boolean().optional(),
  frequency: z.enum(["daily", "weekly", "monthly"], "Please select a valid frequency").optional(),
  bio: z.string().optional(),
});

const registrationSchema = baseSchema.superRefine((values, ctx) => {
  // otherInfo required when role === "contributor"
  if (values.role === "contributor" && (!values.otherInfo || values.otherInfo.trim() === "")) {
    ctx.addIssue({
      path: ["otherInfo"],
      message: "Other information is required for contributors",
      code: "custom",
    });
  }

  // frequency required when newsletter is true
  if (values.newsletter === true && (!values.frequency || values.frequency === "")) {
    ctx.addIssue({
      path: ["frequency"],
      message: "Please select a frequency",
      code: "custom",
    });
  }
});

export type RegistrationFormValues = z.infer<typeof registrationSchema>;
export { registrationSchema };

